(window.webpackJsonp=window.webpackJsonp||[]).push([[194],{821:function(r,e){r.exports="\x3c!-- \r\ntitle: 50-OpenCV\r\nsort: \r\n--\x3e \r\n# OpenCV\r\n\r\n## 安装\r\n\r\n`pip install opencv`\r\n\r\n## 示例程序\r\n\r\n### 调用摄像头\r\n\r\n```python \r\nimport cv2\r\n\r\n# 获取摄像头，传入0表示获取系统默认摄像头\r\ncap = cv2.VideoCapture(0,cv2.CAP_DSHOW)\r\n# 打开cap\r\ncap.open(0)\r\n\r\nwhile cap.isOpened():\r\n    # 获取画面\r\n    flag, frame= cap.read()\r\n    cv2.imshow('my_window',frame)\r\n    # 获取键盘上按下哪个键\r\n    key_pressed=cv2.waitKey(60)\r\n    print('键盘上被按下的键是：',key_pressed)\r\n    # 如果按下esc键，就退出循环\r\n    if key_pressed==27:\r\n        break\r\n# 关闭摄像头\r\ncap.release()\r\n# 关闭图像窗口\r\ncv2.destroyAllWindows()\r\n```\r\n\r\n### 边缘检测\r\n\r\n```python\r\n# 调用摄像头，实时边缘检测\r\nimport cv2\r\nimport numpy as np\r\n\r\n# 获取摄像头，传入0表示获取系统默认摄像头\r\ncap = cv2.VideoCapture(0, cv2.CAP_DSHOW)\r\n# 打开cap\r\ncap.open(0)\r\n\r\nwhile cap.isOpened():\r\n    # 获取画面\r\n    flag, frame = cap.read()\r\n    if not flag:\r\n        break\r\n    # 获取键盘上按下哪个键\r\n    key_pressed = cv2.waitKey(60)\r\n    print('键盘上被按下的键是：', key_pressed)\r\n    # frame=cv2.resize(frame,(100,100))\r\n    # 进行canny边缘检测\r\n    frame = cv2.Canny(frame, 100, 200)\r\n    # 将单通道图像复制三份，累成三通道图像\r\n    frame = np.dstack((frame, frame, frame))\r\n    # 展示处理后的三大通道图像\r\n    cv2.imshow('my_window', frame)\r\n    # 如果按下esc键，就退出循环\r\n    if key_pressed == 27:\r\n        break\r\n\r\n# 关闭摄像头\r\ncap.release()\r\n# 关闭图像窗口\r\ncv2.destroyAllWindows()\r\n```\r\n\r\n### 微笑识别\r\n\r\n```python\r\nimport cv2\r\n\r\n# 载入人脸检测器、眼睛检测器、微笑检测器\r\nface_cascade = cv2.CascadeClassifier(cv2.data.haarcascades+'haarcascade_frontalface_default.xml')\r\n\r\neye_cascade = cv2.CascadeClassifier(cv2.data.haarcascades+'haarcascade_eye.xml')\r\n\r\nsmile_cascade = cv2.CascadeClassifier(cv2.data.haarcascades+'haarcascade_smile.xml')\r\n\r\n# 调用摄像头\r\ncap = cv2.VideoCapture(0)\r\n\r\nwhile(True):\r\n    # 获取摄像头拍摄到的画面\r\n    ret, frame = cap.read()\r\n    faces = face_cascade.detectMultiScale(frame, 1.3, 2)\r\n    img = frame\r\n    for (x,y,w,h) in faces:\r\n    \t# 画出人脸框，蓝色，画笔宽度微\r\n        img = cv2.rectangle(img,(x,y),(x+w,y+h),(255,0,0),2)\r\n    \t# 框选出人脸区域，在人脸区域而不是全图中进行人眼检测，节省计算资源\r\n        face_area = img[y:y+h, x:x+w]\r\n        \r\n        ## 人眼检测\r\n        # 用人眼级联分类器引擎在人脸区域进行人眼识别，返回的eyes为眼睛坐标列表\r\n        eyes = eye_cascade.detectMultiScale(face_area,1.3,10)\r\n        for (ex,ey,ew,eh) in eyes:\r\n            #画出人眼框，绿色，画笔宽度为1\r\n            cv2.rectangle(face_area,(ex,ey),(ex+ew,ey+eh),(0,255,0),1)\r\n        \r\n        ## 微笑检测\r\n        # 用微笑级联分类器引擎在人脸区域进行人眼识别，返回的eyes为眼睛坐标列表\r\n        smiles = smile_cascade.detectMultiScale(face_area,scaleFactor= 1.16,minNeighbors=65,minSize=(25, 25),flags=cv2.CASCADE_SCALE_IMAGE)\r\n        for (ex,ey,ew,eh) in smiles:\r\n            #画出微笑框，红色（BGR色彩体系），画笔宽度为1\r\n            cv2.rectangle(face_area,(ex,ey),(ex+ew,ey+eh),(0,0,255),1)\r\n            cv2.putText(img,'Smile',(x,y-7), 3, 1.2, (0, 0, 255), 2, cv2.LINE_AA)\r\n        \r\n\t# 实时展示效果画面\r\n    cv2.imshow('frame2',img)\r\n    # 每5毫秒监听一次键盘动作\r\n    if cv2.waitKey(5) & 0xFF == ord('q'):\r\n        break\r\n\r\n# 最后，关闭所有窗口\r\ncap.release()\r\ncv2.destroyAllWindows()\r\n```\r\n\r\n"}}]);